import type { FeedCategory } from "./feedArticles";

export interface DailyArticle {
  id: string;
  category: FeedCategory;
  title: string;
  excerpt: string;
  body: string[];
  readTime: string;
  isExternal?: boolean;
  publisher?: string;
  externalUrl?: string;
  publishedAt: number; // unix ms
}

/* ── helper: date for an article published N days ago ── */
function daysAgo(n: number): number {
  const d = new Date();
  d.setHours(10, 0, 0, 0);
  d.setDate(d.getDate() - n);
  return d.getTime();
}

/* ── Pool: 10 articles per category (internal), 12 external ──
   Each day 5 per category are "active" (day-index rotation)
   so the cycle repeats every 2 days. */

export const POOL_INTERNAL: DailyArticle[] = [

  /* ── ENGINEERING ── */
  { id:"di-eng-01", category:"engineering", publishedAt: daysAgo(0), readTime:"4 min read",
    title:"The Rise of Digital Twins in Engineering",
    excerpt:"Digital twin technology is transforming how engineers design, test, and maintain complex systems — from jet engines to smart city infrastructure.",
    body:["A digital twin is a virtual replica of a physical asset, updated in real time by sensor data. Engineers at GE, Siemens, and NASA now use digital twins to run thousands of failure simulations before a single bolt is tightened — dramatically reducing costly real-world errors.","**Why It Matters for Students:** Understanding digital twin platforms (like Azure Digital Twins or PTC ThingWorx) is rapidly becoming a baseline expectation for engineering graduates at major manufacturers. Students who build familiarity now will enter the workforce ahead of the curve.","**Key Applications:** Power grid optimization, aircraft engine monitoring, autonomous vehicle validation, and smart building energy management are among the most active use cases — and each represents a career growth area."]},
  { id:"di-eng-02", category:"engineering", publishedAt: daysAgo(0), readTime:"3 min read",
    title:"Structural Engineering After Natural Disasters",
    excerpt:"When earthquakes, floods, and hurricanes strike, structural engineers are the first professionals called to assess what stands and what must come down.",
    body:["Structural engineers play a critical role in disaster response, performing rapid safety assessments of buildings, bridges, and infrastructure in the immediate aftermath of a catastrophic event.","**The ATC-20 Protocol:** In the U.S., trained engineers use the Applied Technology Council's ATC-20 procedures to post-disaster inspect buildings and tag them Green (safe), Yellow (restricted use), or Red (unsafe). Learning this system is part of professional development for any structural engineer working in seismically or storm-active regions.","Building a career in structural engineering with disaster-resilience expertise means you'll always be needed — because the climate is making extreme events more frequent, not less."]},
  { id:"di-eng-03", category:"engineering", publishedAt: daysAgo(1), readTime:"5 min read",
    title:"Hydrogen Energy: The Role of Mechanical Engineers",
    excerpt:"Green hydrogen is being called the fuel of the 21st century. Here's why mechanical engineers are at the center of making it a reality.",
    body:["Green hydrogen — produced by splitting water molecules with renewable energy — generates zero emissions when burned. Governments and corporations have pledged hundreds of billions toward building hydrogen infrastructure, and mechanical engineers are the backbone of every project.","**What the Work Looks Like:** ME's design electrolyzers, fuel cells, storage tanks, and distribution pipelines. The thermodynamics, materials science, and fluid mechanics skills developed in a mechanical engineering degree translate directly to hydrogen system design.","**Entry Points for Students:** Internships at companies like Plug Power, Nel Hydrogen, Air Products, and Bloom Energy offer hands-on exposure. A degree in ME, ChE, or materials engineering is the typical pathway in."]},
  { id:"di-eng-04", category:"engineering", publishedAt: daysAgo(1), readTime:"4 min read",
    title:"Controls Engineering: The Unsung Hero of Modern Automation",
    excerpt:"Every automated factory, autonomous vehicle, and smart appliance runs on control systems. Yet most students have never heard of controls engineering.",
    body:["Controls engineering — also called control systems engineering — is the discipline responsible for making machines behave predictably and safely. It combines mechanical engineering, electrical engineering, and applied mathematics to design feedback systems.","**Real-World Roles:** Controls engineers work on autopilot systems, industrial robot arms, HVAC regulation, power plant safety systems, and self-driving vehicle algorithms. The median salary exceeds $95,000 and the field is projected to grow significantly as automation expands.","If you enjoy math — especially differential equations and linear algebra — and want a career in automation without going fully into software, controls engineering deserves serious consideration."]},
  { id:"di-eng-05", category:"engineering", publishedAt: daysAgo(2), readTime:"4 min read",
    title:"What Mechanical Engineers Do at Tesla",
    excerpt:"Inside one of the most ambitious manufacturing operations on Earth — and the engineers who make it run.",
    body:["Tesla employs mechanical engineers across vehicle design, battery systems, thermal management, manufacturing tooling, and Autopilot hardware integration. The breadth of work is extraordinary compared to traditional OEM automakers.","**Design → Validation → Manufacturing:** At Tesla, ME's move faster than at legacy automakers because the company operates more like a tech startup than a traditional car company. Expect tight timelines, rapid iteration, and cross-functional collaboration with software and electrical teams.","For engineering students interested in EVs, building skills in battery thermal management, CAD (CATIA, SolidWorks), and manufacturing simulation will make you highly competitive for Tesla roles."]},
  { id:"di-eng-06", category:"engineering", publishedAt: daysAgo(2), readTime:"3 min read",
    title:"Ocean Engineering: Careers Beneath the Surface",
    excerpt:"Ocean engineers design the infrastructure of the underwater world — from offshore oil platforms to submarine cables to deep-sea research vessels.",
    body:["Ocean engineering is a niche but high-demand discipline that addresses the unique challenges of building structures and systems in saltwater marine environments. The combination of hydrodynamics, materials corrosion science, and structural mechanics is unlike any other field.","**Key Employers:** Offshore energy companies (Shell, Equinor, Chevron), U.S. Navy contractors, NOAA, and academic marine research institutions are the major employers. Entry-level salaries typically start around $75,000–$90,000.","The growing offshore wind energy sector — particularly in the U.S. Northeast and Europe — is creating significant new demand for ocean engineers who understand marine foundation design and cable routing."]},
  { id:"di-eng-07", category:"engineering", publishedAt: daysAgo(3), readTime:"4 min read",
    title:"How Much Do Engineers Actually Make? A Realistic Breakdown",
    excerpt:"Salary ranges in engineering vary widely by discipline, employer type, and geography. Here is an honest, category-by-category breakdown for 2026.",
    body:["Engineering salaries are among the highest of any undergraduate major, but the range is broad. Software engineers at FAANG companies can earn $200K+ total compensation out of school, while a civil engineer at a municipal agency may start at $65K. Context matters.","**Median Entry-Level Salaries (2026 data):**\n• Software Engineering: $115,000–$135,000\n• Aerospace: $90,000–$105,000\n• Mechanical: $78,000–$95,000\n• Electrical: $85,000–$100,000\n• Civil: $65,000–$82,000\n• Biomedical: $75,000–$92,000\n• Chemical: $85,000–$100,000","Geography plays a massive role. The same civil engineering job paying $75K in the Midwest may pay $115K in San Francisco — but costs of living differ just as dramatically. When comparing offers, always calculate purchasing power, not raw salary."]},
  { id:"di-eng-08", category:"engineering", publishedAt: daysAgo(3), readTime:"3 min read",
    title:"Engineering Internships: What Recruiters Actually Look For",
    excerpt:"Thousands of students apply to engineering internships every year. A small percentage land them. Here's what separates the ones who do.",
    body:["Engineering recruiters at top companies look for three things above all else: demonstrated technical skills, problem-solving evidence (projects, hackathons, coursework), and communication ability. GPA matters but is rarely the primary filter.","**What Stands Out:** A personal project on GitHub, a competition robot, a research paper, or a technical blog post signals that you care enough to build outside of class. Recruiters see thousands of 3.7 GPAs — they rarely see students who built a working drone stabilization system.","Apply early (September–November for summer internships), tailor your resume to each role, and prepare to explain every item on your resume in technical detail. If you can't explain it, don't list it."]},
  { id:"di-eng-09", category:"engineering", publishedAt: daysAgo(4), readTime:"5 min read",
    title:"The Real Difference Between a BS and MS in Engineering",
    excerpt:"When should you go straight to work after a bachelor's? When is a master's degree worth the time and cost?",
    body:["A bachelor's in engineering opens most entry-level doors. A master's degree opens the doors to higher-level technical roles, certain specializations, and academia — but costs two years and substantial tuition.","**When a Master's Makes Sense:** If you want to specialize deeply (e.g., machine learning for robotics, biomedical imaging, structural seismic analysis), pivot to a related field, or pursue research-heavy roles, a master's provides genuine value.","**When to Go Straight to Work:** If your employer offers tuition reimbursement, starting work first and completing a part-time MS is financially smarter. Many major employers (Lockheed, Boeing, Intel, Honeywell) pay for master's degrees for high-performing early-career engineers."]},
  { id:"di-eng-10", category:"engineering", publishedAt: daysAgo(4), readTime:"4 min read",
    title:"Engineering Ethics: Why They Matter More Than Ever",
    excerpt:"From the Boeing 737 MAX crashes to the Flint water crisis — engineering decisions have life-or-death consequences. Ethics education is non-negotiable.",
    body:["Every major engineering disaster in the past 50 years has had an ethical failure at its core — a decision made under pressure, profit, or organizational culture that overrode sound engineering judgment.","**What Engineering Ethics Covers:** Professional responsibility, whistleblower protections, conflicts of interest, public safety obligations, and the ethical use of emerging technologies (AI, autonomous systems, bioengineering).","Every licensed Professional Engineer (PE) in the United States is bound by NSPE's Code of Ethics. Learning to recognize ethical dilemmas — and having the vocabulary to address them — is a career-long skill, not a one-semester box to check."]},

  /* ── BUSINESS ── */
  { id:"di-biz-01", category:"business", publishedAt: daysAgo(0), readTime:"4 min read",
    title:"What Investment Bankers Actually Do All Day",
    excerpt:"The glamour of investment banking is real — but so is the grind. A clear-eyed look at the day-to-day reality of one of finance's most demanding careers.",
    body:["Investment bankers advise companies on mergers, acquisitions, IPOs, and capital raises. At the analyst level (fresh out of undergrad), the role is primarily financial modeling, pitch book creation, and deal due diligence — with extremely long hours.","**The Hours Are Real:** 80–100 hour weeks during active deals are standard at bulge bracket banks. Many analysts burn out within two years. But those who survive often exit to private equity, hedge funds, or top MBA programs — or build toward managing director roles.","The pay is exceptional: first-year analysts at Goldman Sachs, JP Morgan, and Morgan Stanley now earn $110,000–$130,000 base before bonuses. But the compensation reflects the time commitment. Know what you're signing up for."]},
  { id:"di-biz-02", category:"business", publishedAt: daysAgo(0), readTime:"3 min read",
    title:"Supply Chain Management: The Career Pandemic Made Famous",
    excerpt:"COVID-19 exposed just how fragile global supply chains are. It also created massive demand for supply chain professionals who can prevent the next breakdown.",
    body:["Supply chain management involves planning, sourcing, manufacturing, and delivering products efficiently from raw materials to end customers. The pandemic — with its empty shelves, semiconductor shortages, and shipping delays — showed the world how critical this field is.","**Career Paths:** Procurement analyst, demand planner, logistics coordinator, operations manager, supply chain director. Starting salaries range from $55,000–$75,000 with rapid advancement potential.","A business degree with a supply chain concentration, or a supply chain management major, is the standard path. Certifications like APICS CSCP or CLTD add significant value in job searches."]},
  { id:"di-biz-03", category:"business", publishedAt: daysAgo(1), readTime:"4 min read",
    title:"Private Equity: How to Break In as a 22-Year-Old",
    excerpt:"Private equity is one of the most competitive and lucrative finance careers. Here's what the realistic path actually looks like.",
    body:["Private equity firms acquire companies, improve their operations, and sell them for a profit. The analysts and associates who support these deals are among the highest-compensated finance professionals in the world — but getting in requires a very specific track record.","**The Standard Path:** Two years as an investment banking analyst at a top-tier bank, followed by a PE associate role. Some firms recruit directly from undergrad at top universities (Harvard, Wharton, Princeton) but it's uncommon outside the biggest firms.","**Alternative Paths:** Consulting at McKinsey or Bain → PE is increasingly viable. Finance roles at late-stage startups or growth equity firms can also serve as entry points into the broader private markets ecosystem."]},
  { id:"di-biz-04", category:"business", publishedAt: daysAgo(1), readTime:"3 min read",
    title:"Marketing in 2026: What the Job Actually Requires",
    excerpt:"The marketing landscape has shifted dramatically with AI, short-form video, and privacy regulations. Here's what skills actually matter for a marketing career today.",
    body:["Marketing has always been about understanding human behavior and communicating value. But the technical dimension of the profession has exploded: data analysis, A/B testing, paid media platforms, SEO, email automation, and AI-generated content are now table stakes.","**Most In-Demand Roles:** Performance marketing manager, growth marketer, content strategist, marketing analytics manager, and product marketing manager command the strongest salaries — typically $65,000–$110,000 for mid-level roles.","Students who combine creativity with data literacy — meaning they can write compelling copy AND analyze campaign metrics — will significantly outperform pure creatives or pure analysts in the job market."]},
  { id:"di-biz-05", category:"business", publishedAt: daysAgo(2), readTime:"5 min read",
    title:"Consulting vs. Industry: Which First Job Wins?",
    excerpt:"The age-old debate for business graduates: join a consulting firm or go directly into an industry role? The answer depends entirely on your goals.",
    body:["Management consulting firms like McKinsey, BCG, and Bain offer exposure to dozens of industries and business problems in the first two to three years. Industry roles offer deeper domain expertise and often clearer advancement tracks within one sector.","**When Consulting Wins:** If you're unsure which industry you want to commit to, consulting lets you sample multiple. It also builds analytical and presentation skills that transfer anywhere. The alumni network of a top consulting firm is extraordinarily valuable.","**When Industry Wins:** If you know exactly what you want to do — say, work in tech product management or finance at a specific type of firm — going directly in is faster and often pays more immediately. Consulting exit opportunities are great, but they're not the only path."]},
  { id:"di-biz-06", category:"business", publishedAt: daysAgo(2), readTime:"3 min read",
    title:"Human Resources: The Career That Manages Every Other Career",
    excerpt:"HR professionals shape company culture, manage compensation, handle conflict, and develop talent. It's a career that's evolving rapidly with AI.",
    body:["Human resources is often misunderstood as a purely administrative function. Modern HR — especially at growth-stage companies and large corporations — is a strategic role that directly impacts organizational performance.","**Key Specializations:** Talent acquisition (recruiting), compensation and benefits, HRBP (HR business partnering), L&D (learning and development), and DEIB (diversity, equity, inclusion, belonging). Each sub-field has distinct skill requirements.","HR professionals with data skills — who can analyze turnover rates, compensation benchmarking data, and engagement survey results — are in significantly higher demand and command higher salaries than generalists."]},
  { id:"di-biz-07", category:"business", publishedAt: daysAgo(3), readTime:"4 min read",
    title:"The MBA: Is It Still Worth $200,000 in 2026?",
    excerpt:"MBA applications are declining at some schools and surging at others. Here's how to think about whether a top business school is the right investment for your career.",
    body:["A top-20 MBA (Harvard, Wharton, Stanford, Booth, Kellogg) still provides enormous ROI for certain career pivots — especially into consulting, private equity, and general management. The average Wharton MBA grad earns $175,000+ immediately after graduation.","**When It Makes Financial Sense:** Career changers (e.g., engineer → product manager, military officer → business), people targeting PE or consulting who couldn't break in through banking, and those aiming for C-suite leadership roles in large organizations.","**When to Skip It:** If you're in tech and want to stay in tech — the MBA carries less weight than experience and portfolio. Many successful product managers, engineers, and startup founders have no MBA. Evaluate the specific career goal, not the degree in the abstract."]},
  { id:"di-biz-08", category:"business", publishedAt: daysAgo(3), readTime:"3 min read",
    title:"Real Estate Investment: How High Schoolers Can Start Learning Now",
    excerpt:"Real estate is one of the primary wealth-building vehicles in the American economy. High school is not too early to begin understanding how it works.",
    body:["Real estate investment involves purchasing properties to generate rental income or appreciation. Understanding concepts like cap rates, NOI (net operating income), cash-on-cash return, and leverage is the foundation of evaluating any real estate deal.","**Career Paths in Real Estate:** Commercial real estate broker, real estate private equity analyst, REIT analyst, property management, real estate development, and real estate law are all distinct and viable paths.","Start learning now by reading J. Scott's BiggerPockets books, following real estate YouTube channels, and studying your local housing market. Shadowing a real estate agent or attending local investor meetups builds real-world intuition far faster than textbooks."]},
  { id:"di-biz-09", category:"business", publishedAt: daysAgo(4), readTime:"4 min read",
    title:"Product Management: The Career That Sits Between Business and Tech",
    excerpt:"Product managers own the 'why' and 'what' of software products. It's one of the most in-demand roles in tech — and one of the hardest to break into.",
    body:["Product managers (PMs) are responsible for defining what products are built, why, and for whom. They sit at the intersection of engineering, design, and business — translating user needs into product requirements that engineering teams can execute.","**What PMs Actually Do:** Writing product requirements documents, running user interviews, analyzing metrics dashboards, prioritizing backlogs, leading sprint planning, and stakeholder communication. No two days look the same.","**Breaking In:** APM (Associate Product Manager) programs at companies like Google, Meta, Airbnb, and Microsoft are the gold standard entry path. Competition is intense. Strong candidates combine technical credibility (CS coursework or engineering background) with communication and analytical skills."]},
  { id:"di-biz-10", category:"business", publishedAt: daysAgo(4), readTime:"3 min read",
    title:"Financial Planning: The Career That Changes People's Lives",
    excerpt:"Certified Financial Planners help individuals build wealth, plan for retirement, and protect their families. It's a career that combines technical knowledge with deep human connection.",
    body:["Financial planners work with individuals and families to create comprehensive financial plans covering budgeting, investing, tax strategy, insurance, estate planning, and retirement. The CFP (Certified Financial Planner) designation is the gold standard credential.","**Career Models:** Fee-only RIAs (registered investment advisors) charge flat fees for advice; commission-based brokers earn from product sales. Fee-only is generally considered more client-aligned. The shift toward fee-only advisory has accelerated in the past decade.","Entry-level roles (financial planning associate, paraplanner) typically start at $55,000–$70,000. Experienced CFPs at established firms commonly earn $120,000–$200,000+ as they build a book of clients."]},

  /* ── HEALTHCARE ── */
  { id:"di-hc-01", category:"healthcare", publishedAt: daysAgo(0), readTime:"4 min read",
    title:"Nursing in 2026: Demand, Salaries, and Career Paths",
    excerpt:"The nursing shortage in the U.S. has reached crisis levels. Here's what that means for students considering a healthcare career.",
    body:["The U.S. is projected to face a shortage of 78,000 full-time registered nurses by 2025, according to the American Nurses Association. This shortage is creating exceptional job security and salary growth for nursing graduates.","**Degree Pathways:** Associate's (ADN, 2 years) → immediate RN licensure; Bachelor's (BSN, 4 years) → better advancement opportunities; Master's (MSN) → Nurse Practitioner, CRNA, or leadership roles.","NPs (Nurse Practitioners) in high-demand specialties — particularly psychiatric-mental health, family practice, and acute care — are among the most recruited healthcare professionals in the country. The median NP salary exceeds $120,000."]},
  { id:"di-hc-02", category:"healthcare", publishedAt: daysAgo(0), readTime:"5 min read",
    title:"Becoming a Physician: The Real Timeline and Cost",
    excerpt:"Medical school is not 4 years. The real path from high school graduation to licensed physician is 11–16 years. Here's the full picture.",
    body:["The full pathway to becoming a physician: 4 years of undergraduate → 4 years of medical school → 3–7 years of residency (depending on specialty) → optional 1–3 year fellowship for subspecialties. Total: 11–18 years after high school.","**The Cost:** Medical school tuition at private institutions averages $55,000–$65,000 per year. Total medical school debt for students without scholarships or family support often exceeds $250,000. Many physicians spend their early career paying this down.","**The Payoff:** Physicians are among the highest-compensated professionals in the U.S. Specialties like orthopedic surgery, radiology, and cardiology see total compensation of $500,000–$900,000+. Even primary care, the lowest-compensated specialty, averages around $270,000."]},
  { id:"di-hc-03", category:"healthcare", publishedAt: daysAgo(1), readTime:"3 min read",
    title:"Physical Therapy: The Healthcare Career That Rebuilds Lives",
    excerpt:"Physical therapists help patients recover from injuries, surgeries, and neurological conditions — without prescribing drugs or performing surgery.",
    body:["Physical therapists are doctoral-level healthcare providers (Doctor of Physical Therapy, DPT) who evaluate movement dysfunction and create individualized treatment plans. PTs work in hospitals, outpatient clinics, sports facilities, schools, and in-home care settings.","**Why PT Is Growing:** An aging population with more joint replacements, stroke recoveries, and chronic musculoskeletal conditions is driving sustained demand. The BLS projects PT employment to grow 14–17% over the next decade.","Median PT salary sits around $98,000. Sports physical therapists working with professional athletic teams earn significantly more. The DPT degree (3 years post-bachelor's) is now required for all PTs entering the field."]},
  { id:"di-hc-04", category:"healthcare", publishedAt: daysAgo(1), readTime:"4 min read",
    title:"Radiology Technologist vs. Radiologist: What's the Difference?",
    excerpt:"Both work with imaging equipment, but the education, scope of practice, and salary are dramatically different.",
    body:["**Radiology Technologist (RT):** Operates imaging equipment (X-ray, MRI, CT, mammography), positions patients, and produces diagnostic images. Requires a 2-year associate's degree or 4-year bachelor's program. Median salary: $65,000–$85,000.","**Radiologist (MD or DO):** A physician who interprets medical images and provides diagnoses. Requires 4 years of undergrad + 4 years of medical school + 5-year diagnostic radiology residency. Median salary: $400,000–$550,000.","Radiation therapy, nuclear medicine technology, and interventional radiology (which combines imaging with minimally invasive procedures) are adjacent career paths worth exploring for students interested in the imaging field."]},
  { id:"di-hc-05", category:"healthcare", publishedAt: daysAgo(2), readTime:"3 min read",
    title:"Mental Health Counseling: One of Healthcare's Fastest Growing Fields",
    excerpt:"The mental health crisis in America has created extraordinary demand for qualified counselors, therapists, and psychiatrists.",
    body:["Mental health counselors, marriage and family therapists (MFTs), clinical social workers (LCSWs), and psychiatrists all work in mental health — but have different educational pathways and scopes of practice.","**The Demand Is Real:** The U.S. currently has a shortage of 20,000+ mental health providers, according to SAMHSA. Telehealth has partially addressed the geographic gap, but demand continues to outstrip supply.","High school students interested in mental health careers should take AP Psychology, volunteer at crisis lines or youth programs, and research the different licensing pathways — as the required degree and supervised hours vary significantly by license type."]},
  { id:"di-hc-06", category:"healthcare", publishedAt: daysAgo(2), readTime:"4 min read",
    title:"Healthcare Administration: Running the Business Side of Medicine",
    excerpt:"Hospitals, clinics, and health systems need leaders who understand both medicine and management. Healthcare administration is where business meets biology.",
    body:["Healthcare administrators manage the operational, financial, and strategic functions of healthcare organizations. They handle budgeting, regulatory compliance, staffing, facility management, and long-term strategic planning.","**Educational Paths:** MHA (Master of Health Administration), MBA with healthcare concentration, or MHA/MBA dual degree. Some roles are accessible with a bachelor's in business, health sciences, or public health.","Healthcare administration offers strong compensation ($75,000–$150,000+ at director/VP levels) and meaningful impact — because efficient, well-run health systems deliver better patient outcomes."]},
  { id:"di-hc-07", category:"healthcare", publishedAt: daysAgo(3), readTime:"5 min read",
    title:"Dentistry: The Quietly Excellent Healthcare Career",
    excerpt:"Dentistry offers physician-level earning, controllable hours, entrepreneurial ownership opportunities, and extremely high job satisfaction. Here's why more students should consider it.",
    body:["Dentists earn a median salary of $175,000–$230,000, work controllable hours compared to many medical specialties, and can own their own practice by their early 30s. The path is rigorous — 4 years of dental school — but shorter than many medical specialties.","**Specialties Within Dentistry:** Orthodontics, oral and maxillofacial surgery, endodontics, periodontics, and pediatric dentistry all offer additional training (2–6 years of residency) and significantly higher compensation.","Dental school admissions are highly competitive. Strong DAT scores, laboratory science coursework (biology, chemistry, biochemistry), and shadowing a dentist for 100+ hours are key prerequisites. The effort is rewarded by one of the most financially rewarding and lifestyle-friendly healthcare careers."]},
  { id:"di-hc-08", category:"healthcare", publishedAt: daysAgo(3), readTime:"3 min read",
    title:"The Difference Between a Pharmacist and a Pharmacy Technician",
    excerpt:"Both work in pharmacies, but their education, responsibilities, and earning potential are vastly different.",
    body:["**Pharmacy Technician:** Assists pharmacists with filling prescriptions, managing inventory, and patient intake. Requires a high school diploma and certification (CPhT). Median salary: $38,000–$50,000. This is an excellent role for students exploring healthcare before committing to a longer education.","**Pharmacist (PharmD):** A doctoral-level clinician who reviews prescriptions for interactions, counsels patients on medication use, and increasingly provides clinical services (immunizations, medication therapy management). Requires 4 years of pharmacy school after 2–4 years of undergrad. Median salary: $125,000–$145,000.","Clinical pharmacy roles in hospitals and ambulatory care clinics are the fastest-growing area of the profession, offering pharmacists far more clinical autonomy and patient interaction than traditional retail settings."]},
  { id:"di-hc-09", category:"healthcare", publishedAt: daysAgo(4), readTime:"4 min read",
    title:"Occupational Therapy: Helping People Reclaim Their Independence",
    excerpt:"OTs help patients with physical, cognitive, or developmental challenges relearn the everyday activities that give life meaning. It's one of the most human-centered healthcare careers.",
    body:["Occupational therapists evaluate how illness, injury, disability, or developmental conditions affect a person's ability to perform daily activities — bathing, cooking, working, playing — and then design interventions to rebuild those capacities.","**Work Settings:** Hospitals, rehab centers, schools, pediatric clinics, mental health facilities, and home health agencies. Pediatric OT and hand therapy are among the most sought-after specializations.","The OTD (Occupational Therapy Doctorate) is becoming the entry-level degree. The median OT salary is around $93,000, with pediatric and specialist roles earning more. Job growth is projected at 14–17%, driven by aging demographics and expanded scope of practice."]},
  { id:"di-hc-10", category:"healthcare", publishedAt: daysAgo(4), readTime:"4 min read",
    title:"Pre-Med in High School: How to Actually Prepare",
    excerpt:"Most pre-med advice focuses on college. Here's what high school students should be doing right now to build a competitive medical school profile.",
    body:["Medical school admissions ultimately hinge on four things: GPA, MCAT score, clinical experience, and research. High school is the time to build the foundations for all four.","**What To Do Now:** Take AP Biology, AP Chemistry, and AP Psychology. Shadow a physician for 40+ hours minimum. Volunteer at a hospital or clinic. Excel academically in science and math — medical school requires strong fundamentals, not just interest.","Choose a college major you can excel in — it doesn't have to be biology. Some of the strongest med school applicants major in engineering, philosophy, or economics because they stand out with exceptional grades outside the typical bio-major pool."]},

  /* ── TECHNOLOGY ── */
  { id:"di-tech-01", category:"technology", publishedAt: daysAgo(0), readTime:"4 min read",
    title:"AI Engineering vs. Machine Learning Engineering: What's the Difference?",
    excerpt:"Two of the hottest job titles in tech — and a surprising amount of overlap, with some crucial distinctions worth understanding.",
    body:["Machine learning engineers build systems that learn from data: training models, optimizing performance, and deploying to production. AI engineers work at a higher level — orchestrating multiple AI components (LLMs, vision models, agents) into complete product systems.","**Which Pays More:** Both command six-figure salaries. ML Engineers at top companies average $165,000–$230,000. AI Engineers (a newer designation) often earn similarly or more at AI-focused startups and research labs.","For students entering the field: strong Python skills, familiarity with PyTorch or TensorFlow, and hands-on project experience (Kaggle competitions, personal ML projects, research) are the baseline expectations."]},
  { id:"di-tech-02", category:"technology", publishedAt: daysAgo(0), readTime:"3 min read",
    title:"Cybersecurity Careers: Where to Start in 2026",
    excerpt:"Cyber threats are escalating, the talent shortage is severe, and the salaries are exceptional. Here's how to build a career path into one of tech's most important fields.",
    body:["Cybersecurity encompasses roles from security operations center (SOC) analyst to penetration tester, cloud security engineer, and CISO (Chief Information Security Officer). The demand spans every industry — from healthcare to banking to national defense.","**The Skills That Matter Most:** Network fundamentals (TCP/IP, DNS, firewalls), scripting (Python, Bash), understanding of operating systems (Linux is essential), and familiarity with tools like Wireshark, Nmap, Metasploit, and Splunk.","The CompTIA Security+ certification is the most recognized entry-level credential. For students serious about the field, participating in CTF (Capture the Flag) competitions is one of the fastest ways to build real skills and an impressive portfolio."]},
  { id:"di-tech-03", category:"technology", publishedAt: daysAgo(1), readTime:"4 min read",
    title:"Cloud Computing Careers: AWS, Azure, and Google Cloud",
    excerpt:"The shift to cloud infrastructure shows no signs of slowing. Here's what cloud careers look like and which certifications actually open doors.",
    body:["Cloud computing professionals design, build, and manage the infrastructure that powers modern software — from SaaS applications to global CDNs. The three dominant platforms (AWS, Azure, GCP) each have their own ecosystem of tools and career paths.","**Highest Demand Roles:** Cloud solutions architect, DevOps engineer, cloud security engineer, and platform engineer are among the most recruited cloud roles. Median salaries for mid-level professionals range from $130,000 to $175,000.","**Certifications That Matter:** AWS Solutions Architect Associate → Professional is the most recognized path. Azure AZ-104 and Google Professional Cloud Architect are strong alternatives. Hands-on lab work (through AWS Academy, Google Qwiklabs, Microsoft Learn) is more important than the cert alone."]},
  { id:"di-tech-04", category:"technology", publishedAt: daysAgo(1), readTime:"3 min read",
    title:"What Does a UX Designer Actually Do?",
    excerpt:"UX (user experience) design sits at the intersection of psychology, visual design, and product thinking. Here's the honest picture of the career.",
    body:["UX designers research user behavior, prototype interface flows, run usability tests, and collaborate with engineers and product managers to ship well-designed products. They answer the question: 'Is this product easy and satisfying to use?'","**The Work in Practice:** User interviews, journey mapping, wireframing in Figma, usability testing, and presenting design rationale to stakeholders make up most of a UX designer's week. It's a highly collaborative, cross-functional role.","Entry-level UX design roles typically start at $70,000–$85,000. Senior designers at tech companies earn $130,000–$180,000+. The Figma ecosystem dominates the tool landscape; mastering it is non-negotiable."]},
  { id:"di-tech-05", category:"technology", publishedAt: daysAgo(2), readTime:"5 min read",
    title:"Data Science vs. Data Analytics vs. Data Engineering: Which Is Right for You?",
    excerpt:"The data field has fragmented into multiple distinct roles. Here's a clear breakdown of what each one actually does.",
    body:["**Data Analyst:** Analyzes existing data to answer business questions. Tools: SQL, Excel, Tableau/Power BI. Education: bachelor's in any quantitative field. Salary: $65,000–$95,000.","**Data Scientist:** Builds statistical models and ML algorithms to generate insights or predictions. Tools: Python, R, Jupyter, sklearn, pandas. Education: master's or strong quantitative bachelor's. Salary: $100,000–$145,000.","**Data Engineer:** Builds and maintains the pipelines that collect, store, and move data reliably. Tools: SQL, Python, Spark, Airflow, dbt, cloud data warehouses. Salary: $120,000–$160,000. This is currently the most undersupplied data role in the market."]},
  { id:"di-tech-06", category:"technology", publishedAt: daysAgo(2), readTime:"3 min read",
    title:"No-Code and Low-Code: A Career or a Stepping Stone?",
    excerpt:"Tools like Webflow, Bubble, and Airtable let you build products without traditional coding. What does that mean for technology careers?",
    body:["No-code and low-code platforms have made it possible for non-engineers to build functional products — landing pages, internal tools, simple databases, and even web apps. For entrepreneurs and marketers, these tools are transformative.","**What It Is NOT:** A replacement for software engineering careers at complex, high-scale products. No-code platforms have real limitations in performance, customization, and security that enterprise software requires overcoming.","**The Career Opportunity:** No-code developers, Webflow specialists, and automation consultants (building Zapier/Make workflows) are in genuine demand at small businesses and agencies. It's a legitimate freelance and agency career — just with a ceiling that traditional engineering doesn't have."]},
  { id:"di-tech-07", category:"technology", publishedAt: daysAgo(3), readTime:"4 min read",
    title:"The Reality of Game Development as a Career",
    excerpt:"Game development is one of the most creative careers in tech — and one of the most competitive and demanding. Here's the unfiltered truth.",
    body:["The video game industry generates more revenue annually than movies and music combined. Yet game development as a career is widely misunderstood by people outside it.","**The Roles Inside Game Dev:** Game programmer, environment artist, character artist, animator, sound designer, level designer, game producer, QA analyst, and narrative designer are distinct specializations within a game studio.","**The Challenges:** Entry-level game programming roles are extremely competitive. Game studios are known for 'crunch culture' (intense overtime before launches). Many successful game developers started with indie projects and built toward studios — or built successful indie studios themselves."]},
  { id:"di-tech-08", category:"technology", publishedAt: daysAgo(3), readTime:"3 min read",
    title:"DevOps Engineer: What the Role Actually Involves",
    excerpt:"DevOps is one of the fastest-growing job titles in technology. Here's what DevOps engineers actually do and how to build toward the role.",
    body:["DevOps engineers bridge the gap between software development and IT operations. They build and maintain the infrastructure, automation pipelines, and tools that allow development teams to ship software faster and more reliably.","**Core Skills:** CI/CD pipelines (Jenkins, GitHub Actions, GitLab CI), containerization (Docker, Kubernetes), infrastructure as code (Terraform, Ansible), cloud platforms (AWS/Azure/GCP), and monitoring (Prometheus, Grafana, Datadog).","Median salary for mid-level DevOps engineers is $130,000–$155,000. Senior DevOps/platform engineers at enterprise companies earn $175,000–$220,000. This is among the highest-demand roles in enterprise tech."]},
  { id:"di-tech-09", category:"technology", publishedAt: daysAgo(4), readTime:"4 min read",
    title:"How to Build a Portfolio That Actually Gets Tech Jobs",
    excerpt:"Most student portfolios look identical. Here's how to build one that actually makes recruiters stop scrolling.",
    body:["A technology portfolio exists to prove one thing: you can build things that work. The strongest portfolios show projects with real scope, documented decisions, and ideally real users or data.","**What Makes a Project Stand Out:** It solves a real problem (not just a tutorial rehash). It's fully deployed and accessible (not just local). The README explains what you built, why, what challenges you faced, and what you'd do differently.","Three strong, original projects beat twenty tutorial clones. Show depth over breadth. If you can point to a project with actual users, even 10–20 people using something you built, that is more impressive than the most polished tutorial project."]},
  { id:"di-tech-10", category:"technology", publishedAt: daysAgo(4), readTime:"3 min read",
    title:"Blockchain Beyond Bitcoin: Careers in Distributed Systems",
    excerpt:"Blockchain technology has real applications in supply chain, healthcare records, and financial infrastructure. Here's where the legitimate career opportunities are.",
    body:["Blockchain technology (distributed ledgers that maintain tamper-proof records across networks) has moved far beyond cryptocurrency into enterprise applications — particularly in supply chain provenance, healthcare data interoperability, and financial settlement systems.","**Real Career Opportunities:** Blockchain developer (Solidity, Rust, Go), smart contract auditor, decentralized application (dApp) developer, and distributed systems engineer at financial institutions and logistics companies.","Distinguish yourself from crypto hype by focusing on the underlying distributed systems technology. Employers building legitimate blockchain applications value computer science fundamentals and distributed systems knowledge far more than familiarity with specific chains."]},

  /* ── TRADES ── */
  { id:"di-tr-01", category:"trades", publishedAt: daysAgo(0), readTime:"3 min read",
    title:"Electrician: One of the Most Financially Rewarding Trade Careers",
    excerpt:"Master electricians in high-cost cities routinely earn $100,000+. Here's the full career pathway from apprentice to master.",
    body:["Electricians install, maintain, and repair electrical systems in residential, commercial, and industrial buildings. The career pathway is structured through apprenticeship programs — which pay you while you learn.","**The Pathway:** 4–5 year apprenticeship (through IBEW or independent programs) → Journeyman Electrician license → Master Electrician license after additional years of experience. Total time from start to Master: 8–12 years.","**Earnings:** Apprentices start at $20–$25/hour. Journeymen earn $35–$55/hour ($75K–$115K/year). Master electricians who own their own businesses or work in specialized industrial settings regularly earn $120K–$180K+."]},
  { id:"di-tr-02", category:"trades", publishedAt: daysAgo(0), readTime:"4 min read",
    title:"HVAC Technician: The Career That Will Always Be in Demand",
    excerpt:"As long as buildings need heating, cooling, and ventilation — HVAC technicians will have stable, well-paying work.",
    body:["HVAC (Heating, Ventilation, and Air Conditioning) technicians install, maintain, and repair climate control systems in homes, commercial buildings, and industrial facilities. The career requires EPA certification for handling refrigerants and specialized training in electrical, mechanical, and refrigeration systems.","**Education Path:** 6-month to 2-year vocational/technical program or apprenticeship → EPA 608 certification → state licensing (requirements vary). Many community colleges offer HVAC programs for under $10,000 total.","The increasing complexity of modern HVAC systems — smart thermostats, variable-refrigerant-flow systems, geothermal heat pumps, and building automation integration — means HVAC technicians with advanced training command premium rates."]},
  { id:"di-tr-03", category:"trades", publishedAt: daysAgo(1), readTime:"4 min read",
    title:"Construction Management: The Trade Career That Wears a Hard Hat and a Suit",
    excerpt:"Construction managers oversee the people, materials, and timelines of building projects. It's a career that blends technical knowledge with business management.",
    body:["Construction managers plan, coordinate, budget, and supervise construction projects from start to completion. They work with architects, engineers, subcontractors, and clients — managing competing demands, tight budgets, and changing conditions.","**Education Paths:** Bachelor's in construction management, civil engineering, or architecture; or working up from the trades (carpenter, mason, ironworker) into supervisory and management roles.","**Salaries:** Project managers at commercial construction firms earn $90,000–$130,000. Senior construction executives at major GCs (Turner, Skanska, Bechtel) earn $150,000–$250,000+. The industry is experiencing severe management talent shortages as experienced professionals retire."]},
  { id:"di-tr-04", category:"trades", publishedAt: daysAgo(1), readTime:"3 min read",
    title:"CNC Machinist: High-Tech Manufacturing for the Next Generation",
    excerpt:"CNC machinists operate computer-controlled precision equipment that manufactures the parts inside every car, aircraft, and medical device. It's manufacturing for the 21st century.",
    body:["CNC (Computer Numerical Control) machinists program and operate precision cutting tools that manufacture metal and composite parts. The role combines computer programming, mathematics, and hands-on mechanical skills.","**Why It's Evolving:** Modern CNC machining is increasingly software-driven. Machinists who can write G-code programs, use CAM software (Mastercam, Fusion 360), and operate 5-axis mills are commanding starting wages of $28–$40/hour.","The aerospace, defense, medical device, and automotive industries all require large numbers of skilled CNC machinists. The manufacturing skills gap means qualified machinists face practically no unemployment risk in the current market."]},
  { id:"di-tr-05", category:"trades", publishedAt: daysAgo(2), readTime:"3 min read",
    title:"Plumbing: A Trade That Builds Generational Wealth",
    excerpt:"Licensed plumbers who build their own business can achieve financial outcomes that rival many professional careers. Here's the real financial picture.",
    body:["Plumbers install and maintain water, gas, and drainage systems in buildings. It's physically demanding work — but the financial rewards for licensed, business-owning plumbers are exceptional.","**The Earnings Path:** Apprentice plumber ($18–$25/hour) → Journeyman ($35–$55/hour) → Master Plumber (license required for running a business) → business owner ($150K–$300K+ annual revenue potential).","The trades shortage is most acute in plumbing. Many experienced master plumbers are retiring, creating demand that trade schools cannot keep pace with. Students who enter plumbing apprenticeships today are entering a seller's market."]},
  { id:"di-tr-06", category:"trades", publishedAt: daysAgo(2), readTime:"4 min read",
    title:"Solar Installation: The Trade Career of the Energy Transition",
    excerpt:"The solar industry is one of the fastest-growing job sectors in America. Here's what solar installers do and how the career is evolving.",
    body:["Solar photovoltaic (PV) installers mount, connect, and maintain solar panel systems on residential and commercial structures. The U.S. Bureau of Labor Statistics projects solar installer employment to grow 22–27% over the next decade — far faster than almost any other occupation.","**Training and Certification:** NABCEP (North American Board of Certified Energy Practitioners) certification is the industry standard. Most installers complete a short vocational program or learn on the job. Electrical knowledge and comfort working at heights are core requirements.","As battery storage, EV charging integration, and smart grid technology become standard, solar installers with additional electrical and automation training will command significantly higher rates."]},
  { id:"di-tr-07", category:"trades", publishedAt: daysAgo(3), readTime:"3 min read",
    title:"Aviation Mechanic: The Trade Behind Every Safe Flight",
    excerpt:"A&P (Airframe and Powerplant) mechanics keep the aviation industry running. With major airlines facing a technician shortage, demand has never been higher.",
    body:["Aviation mechanics inspect, maintain, and repair aircraft systems including engines, landing gear, avionics, and structural components. Every commercial aircraft requires FAA-certified mechanics for all maintenance work.","**Education:** FAA-approved Aviation Maintenance Technician Schools (AMTS) offer 18–24 month programs. The A&P certificate requires a minimum of 1,900 hours of instruction and FAA written, oral, and practical exams.","The commercial aviation industry is facing its most severe A&P mechanic shortage in decades, driven by rapid fleet expansion and a wave of retirements. Major airlines are offering $30,000–$50,000 signing bonuses and starting pay of $35–$50/hour for newly certified mechanics."]},
  { id:"di-tr-08", category:"trades", publishedAt: daysAgo(3), readTime:"3 min read",
    title:"Industrial Millwright: The Specialist Who Keeps Factories Running",
    excerpt:"Millwrights install, align, repair, and maintain the industrial machinery that powers manufacturing. It's a skilled trade most students have never heard of — with a salary that might surprise you.",
    body:["Industrial millwrights specialize in the precise installation, alignment, and maintenance of heavy industrial machinery — turbines, conveyors, pumps, compressors, and manufacturing equipment. Precision is everything; misalignment by fractions of an inch causes catastrophic failures.","**Earnings:** Experienced millwrights earn $35–$65/hour ($75K–$135K/year), with overtime common during planned plant shutdowns. The work is physically demanding but well-compensated.","Training occurs primarily through IUPAT and United Brotherhood of Carpenters apprenticeship programs. Millwrights with training in vibration analysis, laser alignment, and predictive maintenance are in exceptional demand at power plants, paper mills, and manufacturing facilities."]},
  { id:"di-tr-09", category:"trades", publishedAt: daysAgo(4), readTime:"4 min read",
    title:"Welding: The Career With More Specializations Than Most Professions",
    excerpt:"From underwater welding to pipe welding on oil rigs, the field of welding spans an enormous range of environments, specializations, and salaries.",
    body:["Welders join metal components using heat, pressure, or both. But 'welding' encompasses dozens of distinct processes (MIG, TIG, stick, flux-core, plasma cutting, laser welding) and industries — each with different skill requirements and pay scales.","**High-Demand Specializations:** Certified pipe welder (petroleum infrastructure): $75,000–$110,000. Underwater welder: $85,000–$300,000+ (dangerous but lucrative). Aerospace welder (precision, exotic alloys): $70,000–$95,000.","Community college and vocational school welding programs take 9–18 months. AWS (American Welding Society) certifications are the industry standard for demonstrating competency in specific processes and materials."]},
  { id:"di-tr-10", category:"trades", publishedAt: daysAgo(4), readTime:"3 min read",
    title:"The Truth About Trade School vs. College for Tradespeople",
    excerpt:"The 'college vs. trades' debate is often oversimplified. Here's a more honest comparison of the real financial and career outcomes.",
    body:["Trade school typically costs $10,000–$35,000 and takes 1–2 years. A 4-year university degree averages $100,000–$200,000 in total cost at private institutions. Trade school apprentices often earn $40,000–$55,000 while training — before their peers have graduated college.","**By Age 30:** A master electrician or plumber who started at 18 may have 8–10 years of experience, zero student debt, and earn $90,000–$130,000. A college graduate with debt entering a non-high-earning field may still be paying loans while earning $55,000–$75,000.","The 'right' answer depends entirely on your interests and goals. Trades careers are not backup plans — they are primary careers that require intelligence, skill, and commitment. The stigma is fading fast as salaries and demand make the choice obvious for many students."]},

  /* ── LAW ── */
  { id:"di-law-01", category:"law", publishedAt: daysAgo(0), readTime:"4 min read",
    title:"BigLaw vs. Public Interest Law: Which Is Right for You?",
    excerpt:"'BigLaw' firms pay $225,000+ to first-year associates. Public interest lawyers may earn $55,000. Here's how to think about the choice.",
    body:["'BigLaw' refers to the largest law firms in the country (AmLaw 100) that pay Cravath-scale starting salaries ($225,000 for first-year associates as of 2026). The work is demanding — 70–90 hour weeks during active deals or trials — but the financial rewards are exceptional.","**Public Interest Law:** Government attorneys, prosecutors, public defenders, legal aid lawyers, and NGO counsel serve the public good but earn far less. The PSLF (Public Service Loan Forgiveness) program can forgive remaining federal law school loans after 10 years of qualifying public service.","Most successful law students choose a path based on their values and financial needs. Loan burden matters: $250,000 in law school debt is manageable on a BigLaw salary, but extremely challenging on a public defender's $60,000 starting pay."]},
  { id:"di-law-02", category:"law", publishedAt: daysAgo(0), readTime:"3 min read",
    title:"How to Get Into a Top 14 Law School",
    excerpt:"The T14 law schools dominate BigLaw hiring and federal clerkship placement. Here's what admissions actually looks for.",
    body:["The T14 (Yale, Harvard, Stanford, Columbia, Chicago, NYU, Penn, UVA, Michigan, Duke, Northwestern, Cornell, Georgetown, Vanderbilt) have outsized influence over BigLaw hiring, federal judicial clerkships, and elite public interest positions.","**The Numbers That Matter:** LSAT score and undergraduate GPA (UGPA) are the primary quantitative filters. Harvard's median LSAT is 174; Yale's is 175. Most T14 schools target a 3.7+ GPA median. Diversity of background, work experience, and compelling personal statements matter at the margins.","Start LSAT prep 6–12 months before your target score date. The LSAT is a learnable test — most serious students improve 10–15 points with deliberate preparation. A 175 LSAT can largely compensate for a 3.5 GPA at many T14 schools."]},
  { id:"di-law-03", category:"law", publishedAt: daysAgo(1), readTime:"4 min read",
    title:"Paralegal Careers: The Legal Field Without Law School",
    excerpt:"Paralegals support attorneys with research, drafting, and case management. It's a meaningful legal career accessible without a JD.",
    body:["Paralegals (also called legal assistants) perform substantive legal work under attorney supervision: legal research, document drafting, case file management, deposition preparation, and client communication. They cannot provide legal advice or represent clients in court.","**Education:** An associate's or bachelor's degree in paralegal studies, or a bachelor's in any field plus a paralegal certificate program. The National Association of Legal Assistants (NALA) and NFPA offer voluntary certifications that improve marketability.","**Earnings:** Median paralegal salary is around $59,000, with litigation and corporate paralegals at large firms earning $75,000–$110,000. It's an excellent entry point into the legal field and a viable career in its own right."]},
  { id:"di-law-04", category:"law", publishedAt: daysAgo(1), readTime:"3 min read",
    title:"Intellectual Property Law: Where Tech Meets the Law",
    excerpt:"As AI, biotech, and software become more economically critical, IP law is one of the fastest-growing and highest-compensated legal specializations.",
    body:["Intellectual property (IP) law protects inventions (patents), creative works (copyrights), brand identities (trademarks), and trade secrets. IP attorneys work with clients ranging from individual inventors to Fortune 500 companies and academic institutions.","**Patent Law's Unique Requirement:** Patent prosecution (writing and prosecuting patent applications with the USPTO) requires passing the Patent Bar exam — which requires a technical undergraduate degree in a STEM field. This makes engineering and science undergrads extremely valuable in patent law.","Patent attorneys who combine technical expertise with legal acumen are among the highest-compensated attorneys in any practice area. Patent partner compensation at major IP boutiques regularly exceeds $500,000–$1,000,000+."]},
  { id:"di-law-05", category:"law", publishedAt: daysAgo(2), readTime:"4 min read",
    title:"Criminal Justice vs. Law: Understanding the Career Difference",
    excerpt:"Criminal justice and law are related but distinct fields. Here's a clear breakdown of the career paths in each.",
    body:["**Criminal Justice** is a social science discipline studying crime, law enforcement, corrections, and the judicial system. A CJ degree opens doors to roles in law enforcement, probation/parole, corrections management, security, and criminal investigative work — without requiring a law degree.","**Law (JD):** Becoming an attorney in criminal law requires a JD and passing the bar exam. Criminal defense attorneys and prosecutors typically earn $55,000–$120,000 depending on sector. Partner at a high-profile criminal defense firm can earn $300,000+.","High school students interested in criminal justice should consider whether they're drawn to the investigative/enforcement side (CJ degree + police academy, FBI, DEA) or the advocacy side (pre-law → JD). Both are meaningful — but very different career paths."]},
  { id:"di-law-06", category:"law", publishedAt: daysAgo(2), readTime:"3 min read",
    title:"Family Law: Rewarding, Emotionally Demanding, and In Constant Demand",
    excerpt:"Family law attorneys handle the most personal legal matters people face — divorce, custody, adoption, and domestic violence. Here's the career reality.",
    body:["Family law attorneys represent clients in divorce proceedings, child custody disputes, adoptions, prenuptial agreements, and domestic violence protective orders. The work is emotionally demanding — clients are often in the most stressful moments of their lives.","**Practice Settings:** Solo practitioners, small family law firms, and legal aid organizations are the primary employers. Very few BigLaw firms practice family law. Earnings range from $55,000 at legal aid to $150,000+ at boutique family law firms.","High school counselors, social workers, and family advocates who want to add legal credentials to their impact often find family law a natural fit. Strong interpersonal skills and emotional resilience are as important as legal analytical ability."]},
  { id:"di-law-07", category:"law", publishedAt: daysAgo(3), readTime:"4 min read",
    title:"Corporate Law: What Life as a Transactional Attorney Actually Looks Like",
    excerpt:"Transactional lawyers — the ones doing M&A, capital markets, and private equity deals — have some of the highest-compensated careers in law. Here's the reality.",
    body:["Corporate transactional attorneys advise companies on mergers, acquisitions, financing, securities offerings, and commercial contracts. At top Wall Street firms, they are among the highest-compensated professionals in any field.","**Day-to-Day Reality:** Reviewing and drafting complex transaction documents, negotiating terms with counterparties and opposing counsel, coordinating due diligence teams, and managing deal timelines across multiple time zones. The hours during active deals are intense — 80–100+ hours per week.","The pay reflects the demands: first-year BigLaw associates earn $225,000 + bonus. Partners at top M&A practices earn $2M–$10M+. The path requires exceptional academic credentials, law review, and a strong summer associate offer from a top firm."]},
  { id:"di-law-08", category:"law", publishedAt: daysAgo(3), readTime:"3 min read",
    title:"Law School Alternatives: Careers in Policy, Compliance, and Legal Operations",
    excerpt:"A law degree isn't the only path to a meaningful career in the legal field. Here's a look at the growing ecosystem of legal-adjacent careers.",
    body:["The legal industry has expanded well beyond practicing attorneys. Compliance officers, contract managers, legal operations specialists, policy analysts, and government affairs professionals all work in law-adjacent roles — often without a JD.","**Compliance** is one of the fastest-growing fields: financial services, healthcare, and tech companies pay compliance managers $90,000–$150,000+ to navigate regulatory requirements.","**Legal Operations** (LegalOps) is a newer discipline focused on bringing business management practices to legal departments. LegalOps professionals with backgrounds in business, technology, and process improvement are in increasing demand at large corporations."]},
  { id:"di-law-09", category:"law", publishedAt: daysAgo(4), readTime:"4 min read",
    title:"Law School Debt: The Crisis No One Fully Explains to Pre-Laws",
    excerpt:"$200,000+ in law school debt is the reality for most students at private law schools. Here's how to think about it before you commit.",
    body:["The average private law school graduate leaves with $130,000–$200,000+ in federal and private loan debt. Combined with undergraduate debt, many new attorneys carry $250,000–$350,000 in total student debt entering the legal workforce.","**When It's Manageable:** BigLaw starting pay ($225,000) allows aggressive debt repayment. Two to three years of maximum loan payments can substantially reduce even large debt loads.","**When It's Catastrophic:** A $200,000 debt load entering a $60,000 public defender role creates debt-to-income ratios that are financially crippling. PSLF is a partial solution, but requires 10 years of qualifying payments and specific employment. Research income-driven repayment options and loan forgiveness programs before choosing any law school."]},
  { id:"di-law-10", category:"law", publishedAt: daysAgo(4), readTime:"3 min read",
    title:"How High School Students Can Prepare for a Career in Law",
    excerpt:"Law school admissions rewards students who have demonstrated logical thinking, writing, and real-world engagement. Here's how to start building that foundation now.",
    body:["The LSAT tests logical reasoning, analytical thinking, and reading comprehension — skills that develop over years, not months. High school is the right time to start building them intentionally.","**What to Do Now:** Take AP English Language, AP Government, and AP History. Join debate team — the skills of constructing arguments and analyzing counterarguments translate directly to LSAT preparation and law school success. Read dense nonfiction and legal journalism (SCOTUSblog, law school faculty blogs).","Shadow an attorney for a day. Visit a local courthouse and observe real hearings. Volunteering at legal aid clinics as a non-legal support person gives you authentic exposure to legal work that will strengthen both your law school application and your certainty that law is the right path."]},

  /* ── SCIENCE ── */
  { id:"di-sci-01", category:"science", publishedAt: daysAgo(0), readTime:"4 min read",
    title:"Research Science vs. Industry Science: Which Career Is Right for You?",
    excerpt:"Academic researchers and industry scientists both do science — but the work, culture, pay, and career trajectory look very different.",
    body:["**Academic Research:** Conducted at universities and research institutes. Primarily funded by grants (NIH, NSF, DOE). The career path is PhD → postdoc (2–5 years) → tenure-track faculty position (highly competitive). Median faculty salary: $80,000–$120,000 with significant prestige and intellectual freedom.","**Industry Research:** Scientists at biotech, pharmaceutical, materials, and technology companies work on applied problems with commercial applications. Faster results timeline, higher immediate salary ($95,000–$160,000 for mid-career researchers), lower prestige, less autonomy.","Many scientists pursue a hybrid path: academia for the PhD and early postdoc work, then transition to industry for financial stability and applied impact. The skills transfer cleanly in both directions."]},
  { id:"di-sci-02", category:"science", publishedAt: daysAgo(0), readTime:"3 min read",
    title:"Forensic Science: What the Career Actually Looks Like (vs. TV)",
    excerpt:"CSI makes forensic science look like detective work. The reality is more precise, more technical, and more evidence-focused — and often more meaningful.",
    body:["Forensic scientists analyze physical evidence — DNA, fingerprints, ballistics, toxicology, digital data, trace materials — in support of criminal investigations and legal proceedings. Unlike TV portrayals, most forensic scientists specialize deeply and work in laboratory settings.","**Key Specializations:** DNA analyst, forensic toxicologist, firearms/toolmarks examiner, digital forensics analyst, and questioned document examiner are distinct disciplines requiring specialized training.","Most forensic science positions require a bachelor's degree in forensic science, chemistry, biology, or a related STEM field. The American Academy of Forensic Sciences (AAFS) certifications add credibility. Starting salaries at state crime labs range from $45,000–$65,000."]},
  { id:"di-sci-03", category:"science", publishedAt: daysAgo(1), readTime:"5 min read",
    title:"The PhD Degree: When to Pursue It, When to Skip It",
    excerpt:"A PhD takes 5–7 years and provides deep expertise. For some careers it's essential; for others it's irrelevant. Here's how to know the difference.",
    body:["A PhD (Doctor of Philosophy) is a research degree that culminates in an original contribution to the knowledge base of your field. It is required for independent research faculty positions and certain advanced research roles in industry. It is not required for most private sector science, engineering, or business careers.","**PhD = Required:** Tenure-track professor at a research university, principal investigator at a biotech company, certain regulatory science roles at FDA, some National Lab scientist positions.","**PhD = Not Required:** Pharmaceutical sales, clinical research associate, data scientist (usually), environmental consultant, science policy analyst, biotechnology manufacturing, science communication.","The decision should be driven by the specific career you want, not by prestige, uncertainty about what to do next, or parental pressure. Talk to professionals working in your target role and ask directly: 'Did you need the PhD to do this work?'"]},
  { id:"di-sci-04", category:"science", publishedAt: daysAgo(1), readTime:"3 min read",
    title:"Environmental Science: Careers at the Intersection of Science and Policy",
    excerpt:"Environmental scientists work on the most consequential problems of the 21st century — climate, water, biodiversity, and pollution.",
    body:["Environmental scientists study the natural world and human impacts on it. The field spans fieldwork (water sampling, wildlife surveys, air quality monitoring), laboratory analysis, data modeling, and policy analysis.","**Career Settings:** Federal agencies (EPA, NOAA, USGS, DOE), state environmental agencies, environmental consulting firms (AECOM, Tetra Tech, Arcadis), NGOs, and corporate sustainability departments.","Bachelor's-level environmental scientists earn $50,000–$70,000 entering the field. Mid-career environmental managers and senior consultants earn $90,000–$130,000. The demand for climate resilience, carbon accounting, and environmental compliance expertise is growing rapidly."]},
  { id:"di-sci-05", category:"science", publishedAt: daysAgo(2), readTime:"4 min read",
    title:"Genetics and Genomics: Careers in the Biological Revolution",
    excerpt:"DNA sequencing has become cheaper than a blood test. Here's what that means for careers in genetics and genomics.",
    body:["Whole-genome sequencing now costs under $200 and takes days — compared to $3 billion and 13 years for the Human Genome Project. This revolution has created an explosion of career opportunities in genetics, genomics, and precision medicine.","**Career Paths:** Genetic counselor (master's degree, helping patients understand genetic test results), research geneticist (PhD), clinical laboratory scientist in molecular diagnostics (bachelor's/master's), bioinformatician (combines biology and computational skills).","The genetic counseling profession is projected to grow 21% over the next decade — one of the fastest growth rates in healthcare. Master's programs in genetic counseling are highly competitive but the career offers exceptional job satisfaction and median salaries of $90,000–$110,000."]},
  { id:"di-sci-06", category:"science", publishedAt: daysAgo(2), readTime:"3 min read",
    title:"Marine Biology: The Career Reality vs. the Dream",
    excerpt:"Marine biology is one of the most popularly dreamed-about careers in science. Here's an honest look at job availability, salaries, and what the work actually involves.",
    body:["Marine biology attracts enormous student interest but has relatively limited full-time research positions. Competition for academic and research positions is intense; most faculty roles require a PhD, multiple postdoctoral positions, and years of grant writing.","**More Accessible Entry Points:** Marine aquarist at public aquariums, environmental consultant specializing in marine ecosystems, dive instructor with marine biology background, science educator or communicator, or roles in fish and wildlife management.","Students who love the ocean and biology but want more stable career outcomes should consider environmental science, fisheries management, environmental engineering (water systems), or marine technology as alternatives with broader job markets."]},
  { id:"di-sci-07", category:"science", publishedAt: daysAgo(3), readTime:"4 min read",
    title:"Food Science: The Science Career Behind Everything You Eat",
    excerpt:"Food scientists develop new products, ensure safety, extend shelf life, and optimize nutrition in the foods we eat. It's a career that blends chemistry, microbiology, and engineering.",
    body:["Food scientists apply chemistry, microbiology, nutrition science, and engineering principles to the development, processing, safety, and quality of food products. They work in food and beverage companies, research institutions, government agencies, and consulting firms.","**What Food Scientists Do:** Developing new food products, analyzing nutritional content, researching food preservation methods, ensuring regulatory compliance, designing food processing equipment, and investigating foodborne illness outbreaks.","The Institute of Food Technologists (IFT) reports starting salaries for food science graduates of $50,000–$70,000, with mid-career professionals earning $85,000–$130,000. The food industry employs food scientists in every country in the world — making it one of the more globally transferable STEM careers."]},
  { id:"di-sci-08", category:"science", publishedAt: daysAgo(3), readTime:"3 min read",
    title:"Climate Science: Careers on the Frontline of the Earth's Future",
    excerpt:"Climate scientists study the mechanisms and impacts of climate change — and their expertise has never been more urgent or in greater demand.",
    body:["Climate scientists use meteorological data, satellite observations, and computer models to understand how Earth's climate is changing and predict future conditions. Their work informs government policy, infrastructure planning, insurance pricing, and agricultural management worldwide.","**Where They Work:** NOAA, NASA, National Weather Service, academic research institutions, international organizations (IPCC, World Meteorological Organization), environmental consulting firms, and hedge funds that trade climate-sensitive commodities.","Most climate science research positions require a PhD in atmospheric science, oceanography, earth science, or a related field. However, bachelor's-level climate analysts find roles in policy, data journalism, and private sector consulting."]},
  { id:"di-sci-09", category:"science", publishedAt: daysAgo(4), readTime:"4 min read",
    title:"Bioinformatics: Where Biology and Computer Science Collide",
    excerpt:"Bioinformatics is one of the fastest-growing science careers — and one of the most interdisciplinary. Here's what bioinformaticians actually do.",
    body:["Bioinformaticians develop computational tools and analyze biological datasets — genomic sequences, protein structures, gene expression data, clinical records — to generate scientific insights. As biological data has grown exponentially, the need for scientists who can write code AND interpret biology has become critical.","**Required Skills:** Python or R programming, statistics, database management (SQL), machine learning basics, and biological domain knowledge (genetics, molecular biology, cell biology).","Bioinformatics roles in biotech and pharma pay exceptionally well: entry-level positions for master's graduates typically start at $85,000–$105,000. PhD bioinformaticians in industry regularly earn $130,000–$175,000 within five years of graduation."]},
  { id:"di-sci-10", category:"science", publishedAt: daysAgo(4), readTime:"3 min read",
    title:"Science Communication: Careers Translating Research for the World",
    excerpt:"Science communicators bridge the gap between scientific research and public understanding. It's a growing field with opportunities in media, museums, nonprofits, and government.",
    body:["Science communicators write, speak, film, and design content that makes complex scientific ideas accessible to non-expert audiences. The field includes science journalists, museum educators, science policy analysts, public information officers for research institutions, and social media science educators.","**Career Paths:** Staff science journalist at a major publication, freelance science writer, public affairs officer at a university or national lab, science exhibit developer at a museum, or YouTube/podcast science educator.","Most science communicators have a bachelor's or master's degree in a science field combined with strong writing, video, or public speaking skills. Internships at science news outlets, museums, or research PR offices provide the most direct path into the field."]},

  /* ── LIFE ADVICE ── */
  { id:"di-la-01", category:"life-advice", publishedAt: daysAgo(0), readTime:"4 min read",
    title:"How to Build Discipline When You Don't Feel Motivated",
    excerpt:"Motivation is unreliable. Discipline is what actually gets things done. Here's how to build it systematically.",
    body:["Motivation is a feeling — and like all feelings, it's temporary and unpredictable. Discipline is a system. High performers in every field — athletes, executives, scientists, artists — do the work whether they feel motivated or not.","**The Habit Architecture:** James Clear's research shows that habits are formed through cue → routine → reward loops. To build disciplined study, work, or practice habits, start absurdly small (5 minutes), attach the habit to an existing cue, and track your consistency visually.","The two most powerful discipline-building strategies: never miss twice (perfection is not the goal — recovery is), and reduce friction to almost zero for the behavior you want and increase friction for the behavior you want to avoid."]},
  { id:"di-la-02", category:"life-advice", publishedAt: daysAgo(0), readTime:"3 min read",
    title:"Networking in High School: Building Relationships That Actually Help Your Career",
    excerpt:"Most students think networking is for adults with business cards. Here's why the relationships you build right now matter more than you think.",
    body:["Every professional was once where you are. The teachers, parents, coaches, and community members around you represent a first-degree network with real connections to career opportunities. The students who understand this early have a massive advantage.","**How to Network as a Student:** Ask questions in class that go beyond the curriculum. Email professors and professionals whose work interests you with specific, thoughtful questions. Attend local professional events and conferences. Volunteer in fields that interest you.","The goal is not to collect contacts. It's to build genuine relationships based on curiosity and reciprocal value. A single strong recommendation from a respected professional can open more doors than a hundred LinkedIn connections."]},
  { id:"di-la-03", category:"life-advice", publishedAt: daysAgo(1), readTime:"5 min read",
    title:"How to Study Smarter, Not Longer: The Science of Effective Learning",
    excerpt:"Most students study in ways that feel productive but aren't. Here's what decades of cognitive science say actually works.",
    body:["Passive re-reading is one of the least effective study methods, yet it's the most commonly used. Research consistently shows that active recall, spaced repetition, and interleaved practice are dramatically more effective for long-term retention.","**Active Recall:** After reading a section, close the book and try to write down everything you remember. This is more uncomfortable than re-reading — and that discomfort is exactly what makes it work.","**Spaced Repetition:** Review material at increasing intervals (1 day, 3 days, 1 week, 2 weeks) rather than in one cramming session. Apps like Anki automate this schedule. The Ebbinghaus forgetting curve shows that spaced review dramatically reduces the rate of forgetting.","**The Pomodoro Technique:** Work in 25-minute focused sessions with 5-minute breaks. After four sessions, take a 30-minute break. This prevents decision fatigue and keeps focus quality high throughout longer study blocks."]},
  { id:"di-la-04", category:"life-advice", publishedAt: daysAgo(1), readTime:"4 min read",
    title:"Choosing a College Major: The Framework That Actually Works",
    excerpt:"Most students pick a major based on vague interest or parental expectation. Here's a more systematic and honest framework.",
    body:["Choosing a college major is one of the most consequential decisions of a young person's life — yet it's typically made with the least information and the most emotional noise.","**The Three-Question Framework:** 1) What subjects do I perform well in and find engaging enough to study for four years? 2) What careers does this major realistically lead to, and am I willing to do that work for 40+ years? 3) Does the financial reality of those careers align with my life goals?","Explore before committing. Use 1WayMirror's career simulations to experience different roles before picking a major. Talk to people working in careers tied to your intended major — not just professors or parents, but actual practitioners at year 5 or 10 of their career."]},
  { id:"di-la-05", category:"life-advice", publishedAt: daysAgo(2), readTime:"4 min read",
    title:"Managing Stress and Anxiety in High School: What Actually Helps",
    excerpt:"Academic pressure, social media, uncertain futures — high school stress is real and increasing. Here's evidence-based guidance that actually helps.",
    body:["Chronic stress during adolescence has measurable effects on cognitive development, physical health, and long-term mental health outcomes. Understanding that and taking it seriously — not dismissing it — is the first step.","**What the Research Supports:** Regular physical exercise (as little as 30 minutes, 3x per week) reduces anxiety symptoms as effectively as many medications for mild-to-moderate cases. Sleep (8–9 hours for adolescents) is non-negotiable for cognitive function and emotional regulation.","Journaling, mindfulness practices, and structured problem-solving (identify what you can control, accept what you cannot) are evidence-based coping tools. If stress and anxiety are persistently interfering with your daily functioning, speaking to a school counselor or therapist is a sign of self-awareness, not weakness."]},
  { id:"di-la-06", category:"life-advice", publishedAt: daysAgo(2), readTime:"3 min read",
    title:"Personal Finance for High Schoolers: What Schools Don't Teach You",
    excerpt:"Compound interest, credit scores, student loans, and investment basics — here's the financial literacy curriculum that should be mandatory.",
    body:["**Compound Interest:** Money invested early grows exponentially over time. A single $5,000 investment at age 18, left untouched at 8% average annual return, becomes approximately $160,000 by retirement. This is why starting even small amounts of saving early has dramatic long-term impact.","**Credit Scores:** Your credit score (300–850) affects your ability to rent an apartment, buy a car, get a mortgage, and sometimes even get a job. It's built by paying bills on time, keeping credit card balances low, and having a long credit history.","**Student Loan Reality:** Borrowing $50,000 for a degree that leads to a $40,000 starting salary creates a debt-to-income ratio that is difficult to manage. Before choosing a college and major, calculate expected starting salary and compare it to the total borrowing. The rule of thumb: borrow no more than your expected first-year salary."]},
  { id:"di-la-07", category:"life-advice", publishedAt: daysAgo(3), readTime:"4 min read",
    title:"Building Emotional Intelligence: The Skill That Predicts Career Success",
    excerpt:"IQ gets you in the room. Emotional intelligence keeps you there. Here's why EQ matters more than most students realize.",
    body:["Daniel Goleman's research on emotional intelligence (EQ) identified five core components: self-awareness, self-regulation, motivation, empathy, and social skills. High EQ predicts leadership effectiveness, workplace relationships, and career advancement more reliably than raw cognitive ability across most industries.","**Developing EQ:** Keep a weekly reflection journal asking: What triggered strong emotions this week? How did I respond? What could I have done differently? This develops the self-awareness that is the foundation of all emotional intelligence.","Practice active listening — focus on understanding what someone means rather than planning your response. Ask clarifying questions. Acknowledge others' perspectives before expressing your own. These habits build social skills and empathy simultaneously."]},
  { id:"di-la-08", category:"life-advice", publishedAt: daysAgo(3), readTime:"3 min read",
    title:"The Gap Year: When It's a Smart Move and When It's Avoidance",
    excerpt:"Taking a year between high school and college can accelerate maturity and career clarity — or it can delay progress. Here's how to tell which it will be for you.",
    body:["Gap years have become more accepted among colleges (Harvard, MIT, and hundreds of others now actively support them), and research suggests students who take structured gap years outperform their peers academically once they return.","**What Makes a Gap Year Productive:** A specific purpose (language immersion, work experience, travel with clear learning goals, service program) with intentional reflection throughout. AmeriCorps, City Year, Peace Corps Prep, and language immersion programs are structured options.","**When a Gap Year Is Avoidance:** Taking an unstructured year with no goals, spending it largely at home, and having no plan for what comes next rarely produces the personal growth or career clarity that productive gap years deliver. Be honest with yourself about the distinction."]},
  { id:"di-la-09", category:"life-advice", publishedAt: daysAgo(4), readTime:"5 min read",
    title:"Writing a College Application Essay That Stands Out",
    excerpt:"Admissions officers at selective colleges read thousands of essays. Here's what makes an essay memorable — and what kills good applications.",
    body:["The college application essay (Common App, Coalition App) is your opportunity to show an admissions committee who you are beyond grades and test scores. At highly selective schools, nearly all applicants have excellent grades. The essay creates differentiation.","**What Works:** Specific, sensory, personal stories that reveal genuine character, self-awareness, or growth. Uncommon angles on ordinary experiences. Genuine voice that sounds like a 17-year-old, not a 45-year-old attempting to impress a committee.","**What Doesn't Work:** Generic 'I learned so much from sports/travel/volunteering' essays that could have been written by anyone. Résumé rehashes. Trying to sound impressive rather than real. Choosing safe, expected topics rather than the specific stories only you can tell.","Start with an honest inventory of your most meaningful, specific, and unusual stories — then find the one that reveals something important about how you think or who you are. Write ten drafts. Share it with a teacher who will be honest, not just supportive."]},
  { id:"di-la-10", category:"life-advice", publishedAt: daysAgo(4), readTime:"3 min read",
    title:"Social Media and Your Future Career: What You Need to Know Now",
    excerpt:"Your digital footprint starts accumulating now — and it lasts. Here's how to build an online presence that helps rather than hurts your career.",
    body:["Approximately 80% of employers research candidates on social media before extending an offer. College admissions offices at selective institutions also review applicants' public social media profiles. What you post now follows you.","**Build a Positive Digital Presence:** Start a LinkedIn profile in 10th or 11th grade. Share your academic and extracurricular achievements. Follow professionals in fields you're interested in and engage thoughtfully with their content. This builds an authentic professional presence over time.","**Protect What Can Harm You:** Review your existing profiles for content that could be misinterpreted or embarrassing to a future employer or admissions officer. The test: would you be comfortable showing every post to the dean of admissions at your dream school? If not, remove or privatize it."]},
];

